-- Q10. What is the revenue contribution of each age group?
select age_group, sum(purchase_amount) as total_revenue
from customer
group by age_group
order by total_revenue desc;

-- q11. who are the top 10 customers contributing the highest revenue? (customer lifetime value)

select customer_id,
       sum(purchase_amount) as total_spent,
       count(*) as total_orders
from customer
group by customer_id
order by total_spent desc
limit 10;


-- q12. what is the revenue contribution percentage of each product category?

select category,
       sum(purchase_amount) as revenue,
       round(100.0 * sum(purchase_amount) / sum(sum(purchase_amount)) over (), 2) as contribution_percentage
from customer
group by category
order by revenue desc;


-- q13. how do discounts impact order value and total revenue?

select discount_applied,
       count(*) as total_orders,
       round(avg(purchase_amount), 2) as avg_order_value,
       sum(purchase_amount) as total_revenue
from customer
group by discount_applied;


-- q14. what percentage of total revenue comes from repeat customers?

select
case 
    when previous_purchases > 5 then 'repeat customers'
    else 'other customers'
end as customer_type,
sum(purchase_amount) as revenue,
round(100.0 * sum(purchase_amount) / sum(sum(purchase_amount)) over (), 2) as revenue_percentage
from customer
group by customer_type;


-- q15. which product categories generate the most high-value orders (above average purchase amount)?

select category,
       count(*) as high_value_orders
from customer
where purchase_amount > (
    select avg(purchase_amount) from customer
)
group by category
order by high_value_orders desc;


-- q16. identify customers at risk of churn (low purchases + long gap between purchases)

select customer_id,
       previous_purchases,
       purchase_frequency_days
from customer
where previous_purchases < 2
  and purchase_frequency_days > 90;